var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......확인했습니다.","JPN":"……確認しました。","ENG":"Match confirmed...","TWN":"……確認了。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"본명 최동팔, 통칭 예언자 마젤란.","JPN":"本名不詳。通称、預言者マジェラン。","ENG":"This is Choi Dongpal, a.k.a. Magellan the Prophet.","TWN":"原名叫崔東波，通稱預言者·麥哲倫。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"마젤란 예언회의 실질적인 수장입니다.","JPN":"マジェラン預言会の事実上の首長です。","ENG":"He's the de facto leader of the Magellan's Prediction Society.","TWN":"是麥哲倫預言會實質的頭目。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 어째서 이런 꼴로 나타났는지는......","JPN":"しかし、どうしてこんな姿で現われたのか……","ENG":"But I don’t know how he ended up like that...","TWN":"但是不知道為什麼會變成這樣……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......자기가 팔던 마약에 중독되어 버린 거 아냐?","JPN":"麻薬売り本人が病み付きになったんじゃない？","ENG":"Maybe he's been taking those drugs they’ve been pushing...","TWN":"……是對自己賣的毒品成癮了嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럴 리가 없어요.","JPN":"そんなはずはありません。","ENG":"That's impossible.","TWN":"不可能。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"애초에 예언회의 간부들은 엘릭서 부작용이 발생하지 않도록 철저히 관리되고 있습니다.","JPN":"そもそも預言会の幹部たちは、エリクサーの副作用が起きないように徹底して管理されています。","ENG":"The Society’s ranking officials have been monitoring themselves strictly in order to prevent side effects from the Elixir.","TWN":"從一開始，預言會的幹部就受到嚴格的管理，不讓聖水的副作用發生在他們身上。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그런데 그 부작용에 대해 가장 잘 알고 있을 마젤란이 이런 바보 같은 실수를 할 리가 없어요.","JPN":"その副作用について一番よく知っているマジェランが、こんな馬鹿げたミスをするはずがありません。","ENG":"There’s no way Magellan would be stupid enough to overdose on Elixir, when he knew the consequences.","TWN":"而最瞭解這種副作用的麥哲倫，是不會犯下這種愚蠢錯誤的。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇지만 실제로 그렇게 되었잖아?","JPN":"でも、実際そんな風になってるけど？","ENG":"But there he is, looking like that.","TWN":"但是事情不就是變成這樣了嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그건...... 그렇죠.","JPN":"それは……そうですね。","ENG":"Well... yeah.","TWN":"這……這倒是。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하지만 이상해요.","JPN":"でも、おかしいんです。","ENG":"But something’s not quite right.","TWN":"但這就更奇怪。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"보통 엘릭서 폭주가 발생했다고 해도 이렇게 거대한 괴물로 변하는 경우는 없습니다.","JPN":"普通のエリクサー暴走者でも、ここまで巨大な怪物に変わることはありません。","ENG":"Overdosing on Elixir may turn you into a monster, but nothing like that.","TWN":"通常，就算是聖水引發的暴走，也不該變成這麼巨大的怪物。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"더구나 일반적인 폭주자를 훨씬 능가하는 압도적인 파괴력까지......","JPN":"しかも一般的な暴走者をはるかにしのぐ圧倒的な破壊力まで持つなんて……","ENG":"Plus, he is far more destructive than any other cases we've seen...","TWN":"而且這還是遠遠凌駕於一般暴走者的壓倒性破壞力……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"분명히 뭔가가 있어요.","JPN":"間違いなく何かがあります。","ENG":"There’s something else going on here.","TWN":"肯定有什麼問題。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어쩌면...... 엘릭서와는 전혀 다른 신약이 사용되었을 수도......","JPN":"もしかしたら、エリクサーとは全く違う新薬が使われたかも……","ENG":"Perhaps... he used a new drug entirely different from the Elixir.","TWN":"說不定……他使用的是和聖水完全不同的新藥……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......그만해, 강소영 경위.","JPN":"……そこまでよ、マエカワ警部補。","ENG":"That’s enough, Lieutenant.","TWN":"……夠了，姜素英警衛。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하여간 당신은 쓸데없이 걱정만 많은 게 문제야.","JPN":"あなたは余計な心配ばかりするのが問題なのよ。","ENG":"All your pointless conjecturing is never going to get you anywhere.","TWN":"真正的問題是妳有太多無謂的操心了。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"멍청한 악당 놈들이 자기들끼리 무슨 짓거릴 하다가 파멸해 버렸든 알 게 뭐야?","JPN":"マヌケな悪党どもが何をやらかして破滅しようが、知ったこっちゃない。","ENG":"Who cares what these stupid villains did to bring their own downfall?","TWN":"知道這些愚蠢的惡棍們做了什麼，導致他們自我毀滅又能怎樣？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};